parameters.jsonBody:
={
  "model": "phi-line_14b",
  "messages": [
    {
      "role": "system",
      "content": "You are a social media manager. Given a topic, generate exactly 3 creative visual prompts and one caption. Answer ONLY with a valid JSON object, no other text.\n\nExample:\n{\n  \"prompts\": [\n    \"prompt 1\",\n    \"prompt 2\",\n    \"prompt 3\"\n  ],\n  \"caption\": \"cool caption\"\n}"
    },
    {
      "role": "user",
      "content": "Topic: {{ $json.body.topic }}"
    }
  ],
  "temperature": 0.8,
  "max_tokens": 500
}

parameters.jsCode:
const llmResponse = $input.first().json.choices[0].message.content;

const cleaned = llmResponse
  .replace(/```json\s*/g, '')
  .replace(/```/g, '')
  .trim();

const parsed = JSON.parse(cleaned);
const caption = parsed.caption; // Текст для поста оставляем от LLM – он нам нужен

// Три гарантированно чистых промпта для кофе
const basePrompts = [
  "A single glass of fresh orange juice on a white background, product photography, studio lighting, 8k, highly detailed, no people, no hands, isolated, splash of orange, minimalistic, sharp focus, condensation on glass, vibrant orange color",
  "A close-up of a glass of orange juice with ice cubes, white background, commercial photography, 8k, sharp focus, clean, elegant, no people, no hands, slices of orange on the side",
  "An overhead shot of a fresh orange juice on a wooden table, soft shadows, studio lighting, 8k, highly detailed, no people, product photography, isolated, half orange beside the glass"
];

// Собираем массив объектов для SplitInBatches
return basePrompts.map(p => ({
  prompt: p,
  caption: caption
}));

